#!/usr/bin/env node
// PreToolUse hook: blocks Write/Edit to protected paths unless env var ALLOW_PROTECTED=1.
// Reads tool input from stdin (Claude Code hook contract).

import { readFileSync } from 'node:fs';

const PROTECTED_PATTERNS = [
  /^migrations\//,
  /^infra\//,
  /^terraform\//,
  /\.env(\..+)?$/,
  /^\.github\/workflows\//,
  /^package-lock\.json$/,
  // Auto-generated by TanStack Router — TanStack Router regenerates this; never hand-edit.
  /routeTree\.gen\.ts$/,
  // This repo's agent control surface: hooks, agent/command/skill defs, settings, and
  // runtime state. Subagents must never rewrite their own guardrails. Anchored with `^`
  // against the project-relative path (see relPath below) so it covers the *repo*
  // .claude/ only — NOT the user-home ~/.claude/ (memory, global settings), which is a
  // legitimate agent-write target. The hooks themselves write state via Node fs (not the
  // Write/Edit tool), so they are unaffected. Human override: ALLOW_PROTECTED=1.
  /^\.claude\//,
];

let raw = '';
try {
  raw = readFileSync(0, 'utf8');
} catch {
  process.exit(0); // no stdin? let it pass
}

let payload;
try {
  payload = JSON.parse(raw);
} catch {
  process.exit(0);
}

const filePath =
  payload?.tool_input?.file_path || payload?.tool_input?.path || '';

// Normalize separators, then make the path relative to the project root when it lives
// inside it. The prefix test is case-insensitive (Windows drive letters / casing), but
// the patterns still match against the original-cased relPath. Paths outside the repo
// (e.g. the user-home ~/.claude/) are left absolute, so the `^`-anchored repo rules
// (including ^\.claude/) cannot match them.
const fwd = filePath.replace(/\\/g, '/');
const cwdFwd = process.cwd().replace(/\\/g, '/');
const relPath = fwd.toLowerCase().startsWith(cwdFwd.toLowerCase() + '/')
  ? fwd.slice(cwdFwd.length + 1)
  : fwd;

if (process.env.ALLOW_PROTECTED === '1') {
  process.exit(0);
}

for (const pat of PROTECTED_PATTERNS) {
  if (pat.test(relPath)) {
    console.error(
      JSON.stringify({
        decision: 'block',
        reason: `Path "${relPath}" is protected. Get explicit human approval, then re-run with ALLOW_PROTECTED=1.`,
      }),
    );
    process.exit(2); // exit code 2 = block in Claude Code hook contract
  }
}

process.exit(0);
